# RLHF deployment: policy + reward model must be served together
class RLHFInference:
    def __init__(self, policy_path, rm_path):
        self.policy = load_model(policy_path)
        self.rm = load_model(rm_path)        # separate model to serve

    def generate_best(self, prompt, n=4):
        responses = [self.policy.generate(prompt) for _ in range(n)]
        scores = [self.rm.score(prompt, r) for r in responses]
        return responses[max(range(n), key=lambda i: scores[i])]


# DPO deployment: only the policy is needed
class DPOInference:
    def __init__(self, policy_path):
        self.policy = load_model(policy_path)
        # No RM loaded — alignment is embedded in the policy weights

    def generate(self, prompt):
        return self.policy.generate(prompt)

    def generate_best_implicit(self, ref_model, prompt, n=4, beta=0.1):
        # Optional: BoN with implicit reward (requires ref_model at inference)
        responses = [self.policy.generate(prompt, do_sample=True) for _ in range(n)]
        scores = [implicit_reward(self.policy, ref_model, prompt, r, beta=beta) for r in responses]
        return responses[max(range(n), key=lambda i: scores[i])]
